/* ---- Privilege Checking System ---- */
static bool check_privilege(uint32_t required_priv, uint32_t task_priv)
{
    return (task_priv & required_priv) == required_priv;
}

static const char *priv_to_string(uint32_t priv)
{
    if (priv == PRIV_ADMIN) return "ADMIN";
    if (priv == PRIV_USER) return "USER";
    if (priv == PRIV_NONE) return "NONE";
    return "CUSTOM";
}

static const char *op_to_string(uint32_t op)
{
    switch (op) {
    case OP_FLASH_WRITE:    return "FLASH_WRITE";
    case OP_CONFIG_MODIFY:  return "CONFIG_MODIFY";
    case OP_CONFIG_READ:    return "CONFIG_READ";
    case OP_STATUS_REQUEST: return "STATUS_REQUEST";
    default:                return "UNKNOWN";
    }
}

/* ---- Flash Operations (Admin Only) ---- */
static int flash_init(void)
{
    k_mutex_lock(&flash_mutex, K_FOREVER);
    memset(simulated_flash, 0xFF, FLASH_SIM_SIZE);
    flash_initialized = true;
    printk("[FLASH] Simulated flash initialized (%d bytes)\n", FLASH_SIM_SIZE);
    k_mutex_unlock(&flash_mutex);
    return 0;
}

static int flash_write(uint32_t offset, const uint8_t *data, uint32_t len,
                       const struct task_identity *identity)
{
    if (!check_privilege(PRIV_WRITE, identity->privilege_level)) {
        printk("[FLASH] DENIED: Task '%s' (priv=%s) attempted flash write\n",
               identity->name, priv_to_string(identity->privilege_level));
        audit_record(identity->task_id, OP_FLASH_WRITE, REQ_DENIED);
        return -EACCES;
    }

    k_mutex_lock(&flash_mutex, K_FOREVER);

    if (!flash_initialized) {
        printk("[FLASH] ERROR: Flash not initialized\n");
        k_mutex_unlock(&flash_mutex);
        return -EIO;
    }

    if (offset + len > FLASH_SIM_SIZE) {
        printk("[FLASH] ERROR: Write out of bounds (offset=%u, len=%u)\n",
               offset, len);
        k_mutex_unlock(&flash_mutex);
        return -EINVAL;
    }

    memcpy(&simulated_flash[offset], data, len);
    printk("[FLASH] Task '%s' wrote %u bytes at offset %u\n",
           identity->name, len, offset);

    audit_record(identity->task_id, OP_FLASH_WRITE, REQ_COMPLETED);
    k_mutex_unlock(&flash_mutex);
    return 0;
}

static int flash_read(uint32_t offset, uint8_t *data, uint32_t len,
                      const struct task_identity *identity)
{
    if (!check_privilege(PRIV_READ, identity->privilege_level)) {
        printk("[FLASH] DENIED: Task '%s' cannot read flash\n", identity->name);
        return -EACCES;
    }

    k_mutex_lock(&flash_mutex, K_FOREVER);

    if (!flash_initialized) {
        k_mutex_unlock(&flash_mutex);
        return -EIO;
    }

    if (offset + len > FLASH_SIM_SIZE) {
        k_mutex_unlock(&flash_mutex);
        return -EINVAL;
    }

    memcpy(data, &simulated_flash[offset], len);
    printk("[FLASH] Task '%s' read %u bytes from offset %u\n",
           identity->name, len, offset);

    k_mutex_unlock(&flash_mutex);
    return 0;
}

