static int config_read(const char *key, char *value, uint32_t val_len,
                       const struct task_identity *identity)
{
    int ret = -ENOENT;

    k_mutex_lock(&config_mutex, K_FOREVER);

    for (int i = 0; i < MAX_CONFIG_ENTRIES; i++) {
        if (system_config[i].in_use &&
            strncmp(system_config[i].key, key, CONFIG_KEY_LEN) == 0) {

            if (!check_privilege(system_config[i].min_priv_read,
                                 identity->privilege_level)) {
                printk("[CONFIG] DENIED: Task '%s' cannot read key '%s' "
                       "(requires priv=%s)\n",
                       identity->name, key,
                       priv_to_string(system_config[i].min_priv_read));
                audit_record(identity->task_id, OP_CONFIG_READ, REQ_DENIED);
                ret = -EACCES;
                break;
            }

            strncpy(value, system_config[i].value, val_len - 1);
            value[val_len - 1] = '\0';
            printk("[CONFIG] Task '%s' read key '%s' = '%s'\n",
                   identity->name, key, value);
            audit_record(identity->task_id, OP_CONFIG_READ, REQ_COMPLETED);
            ret = 0;
            break;
        }
    }

    k_mutex_unlock(&config_mutex);
    return ret;
}

static int config_modify(const char *key, const char *value,
                         const struct task_identity *identity)
{
    int ret = -ENOENT;
    int free_slot = -1;

    k_mutex_lock(&config_mutex, K_FOREVER);

    /* Search for existing key or free slot */
    for (int i = 0; i < MAX_CONFIG_ENTRIES; i++) {
        if (system_config[i].in_use &&
            strncmp(system_config[i].key, key, CONFIG_KEY_LEN) == 0) {

            if (!check_privilege(system_config[i].min_priv_write,
                                 identity->privilege_level)) {
                printk("[CONFIG] DENIED: Task '%s' cannot modify key '%s' "
                       "(requires priv=%s)\n",
                       identity->name, key,
                       priv_to_string(system_config[i].min_priv_write));
                audit_record(identity->task_id, OP_CONFIG_MODIFY, REQ_DENIED);
                ret = -EACCES;
                goto out;
            }

            strncpy(system_config[i].value, value, CONFIG_VAL_LEN - 1);
            system_config[i].value[CONFIG_VAL_LEN - 1] = '\0';
            printk("[CONFIG] Task '%s' modified key '%s' = '%s'\n",
                   identity->name, key, value);
            audit_record(identity->task_id, OP_CONFIG_MODIFY, REQ_COMPLETED);
            ret = 0;
            goto out;
        }
        if (!system_config[i].in_use && free_slot < 0) {
            free_slot = i;
        }
    }

    /* Key not found - create new entry if admin */
    if (free_slot >= 0) {
        if (!check_privilege(PRIV_ADMIN, identity->privilege_level)) {
            printk("[CONFIG] DENIED: Task '%s' cannot create new config entries\n",
                   identity->name);
            audit_record(identity->task_id, OP_CONFIG_MODIFY, REQ_DENIED);
            ret = -EACCES;
            goto out;
        }

        strncpy(system_config[free_slot].key, key, CONFIG_KEY_LEN - 1);
        system_config[free_slot].key[CONFIG_KEY_LEN - 1] = '\0';
        strncpy(system_config[free_slot].value, value, CONFIG_VAL_LEN - 1);
        system_config[free_slot].value[CONFIG_VAL_LEN - 1] = '\0';
        system_config[free_slot].in_use = true;
        system_config[free_slot].min_priv_read = PRIV_READ;
        system_config[free_slot].min_priv_write = PRIV_WRITE;

        printk("[CONFIG] Task '%s' created new key '%s' = '%s'\n",
               identity->name, key, value);
        audit_record(identity->task_id, OP_CONFIG_MODIFY, REQ_COMPLETED);
        ret = 0;
    } else {
        printk("[CONFIG] ERROR: No free config slots\n");
        ret = -ENOMEM;
    }

out:
    k_mutex_unlock(&config_mutex);
    return ret;
}

static void config_dump(const struct task_identity *identity)
{
    k_mutex_lock(&config_mutex, K_FOREVER);
    printk("[CONFIG] --- System Configuration Dump (by '%s') ---\n",
           identity->name);

    for (int i = 0; i < MAX_CONFIG_ENTRIES; i++) {
        if (system_config[i].in_use) {
            if (check_privilege(system_config[i].min_priv_read,
                                identity->privilege_level)) {
                printk("[CONFIG]   [%d] '%s' = '%s' (read_priv=%s, write_priv=%s)\n",
                       i, system_config[i].key, system_config[i].value,
                       priv_to_string(system_config[i].min_priv_read),
                       priv_to_string(system_config[i].min_priv_write));
            } else {
                printk("[CONFIG]   [%d] '%s' = <ACCESS DENIED>\n",
                       i, system_config[i].key);
            }
        }
    }
    printk("[CONFIG] --- End Dump ---\n");
    k_mutex_unlock(&config_mutex);
}

/* ---- Privilege Escalation Request System ---- */
static int submit_request(struct operation_request *req)
{
    k_mutex_lock(&request_mutex, K_FOREVER);
    memcpy(&pending_request, req, sizeof(struct operation_request));
    pending_request.status = REQ_PENDING;
    k_mutex_unlock(&request_mutex);

    printk("[PRIV] Request submitted: task_id=%u, op=%s\n",
           req->requester_id, op_to_string(req->operation));

    /* Signal admin that a request is waiting */
    k_sem_give(&request_sem);

    /* Wait for admin to process */
    if (k_sem_take(&response_sem, K_MSEC(5000)) != 0) {
        printk("[PRIV] Request timed out waiting for admin\n");
        return -ETIMEDOUT;
    }

    /* Copy result back */
    k_mutex_lock(&request_mutex, K_FOREVER);
    req->status = pending_request.status;
    req->result_code = pending_request.result_code;
    k_mutex_unlock(&request_mutex);

    return req->result_code;
}

static int process_request(struct operation_request *req,
                           const struct task_identity *admin_identity)
{
    int ret = 0;

    printk("[ADMIN] Processing request: op=%s from task_id=%u (priv=%s)\n",
           op_to_string(req->operation), req->requester_id,
           priv_to_string(req->requester_priv));

    /* Validate that the processor is actually admin */
    if (!check_privilege(PRIV_ADMIN, admin_identity->privilege_level)) {
        printk("[ADMIN] ERROR: Non-admin attempting to process requests!\n");
        req->status = REQ_DENIED;
        req->result_code = -EACCES;
        return -EACCES;
    }

    switch (req->operation) {
    case OP_FLASH_WRITE:
        printk("[ADMIN] Executing flash write on behalf of task %u\n",
               req->requester_id);
        ret = flash_write(req->flash_offset, req->data, req->data_len,
                          admin_identity);
        break;

    case OP_CONFIG_MODIFY:
        printk("[ADMIN] Executing config modify on behalf of task %u\n",
               req->requester_id);
        ret = config_modify(req->config_key, req->config_value,
                            admin_identity);
        break;

    case OP_CONFIG_READ:
        printk("[ADMIN] Executing config read on behalf of task %u\n",
               req->requester_id);
        ret = config_read(req->config_key, req->config_value,
                          CONFIG_VAL_LEN, admin_identity);
        break;

    case OP_STATUS_REQUEST:
        printk("[ADMIN] Status request from task %u - system OK\n",
               req->requester_id);
        ret = 0;
        break;

    default:
        printk("[ADMIN] Unknown operation: %u\n", req->operation);
        ret = -EINVAL;
        break;
    }

    req->result_code = ret;
    req->status = (ret == 0) ? REQ_COMPLETED : REQ_DENIED;

    audit_record(req->requester_id, req->operation, req->status);
    return ret;
}

/* ---- Admin Task ---- */
static void admin_task(void *p1, void *p2, void *p3)
{
    ARG_UNUSED(p1);
    ARG_UNUSED(p2);
    ARG_UNUSED(p3);

    struct task_identity admin_id = {
        .task_id = 0,
        .privilege_level = PRIV_ADMIN,
        .name = "admin"
    };

    printk("[ADMIN] Admin task started (priv=%s)\n",
           priv_to_string(admin_id.privilege_level));

    /* Initialize subsystems */
    flash_init();
    config_init();

    /* Admin performs its own direct operations first */
    printk("\n[ADMIN] === Performing direct admin operations ===\n");

    /* Direct flash write */
    uint8_t boot_data[] = {0xDE, 0xAD, 0xBE, 0xEF, 0xCA, 0xFE};
    flash_write(0, boot_data, sizeof(boot_data), &admin_id);

    /* Direct config modification */
    config_modify("hostname", "admin-device-01", &admin_id);
    config_modify("boot_count", "42", &admin_id);

    /* Dump config as admin (can see everything) */
    config_dump(&admin_id);

    printk("[ADMIN] === Direct operations complete, entering request loop ===\n\n");

    /* Main loop: process user requests */
    while (1) {
        /* Wait for a request from user task */
        if (k_sem_take(&request_sem, K_MSEC(2000)) == 0) {
            struct operation_request local_req;

            k_mutex_lock(&request_mutex, K_FOREVER);
            memcpy(&local_req, &pending_request, sizeof(local_req));
            k_mutex_unlock(&request_mutex);

            /* Process the request with admin privileges */
            process_request(&local_req, &admin_id);

            /* Send result back */
            k_mutex_lock(&request_mutex, K_FOREVER);
            memcpy(&pending_request, &local_req, sizeof(local_req));
            k_mutex_unlock(&request_mutex);

            k_sem_give(&response_sem);
        } else {
            /* Periodic admin maintenance */
            printk("[ADMIN] Heartbeat - no pending requests\n");

            /* Periodically print audit log */
            static int heartbeat_count = 0;
            heartbeat_count++;
            if (heartbeat_count % 5 == 0) {
                audit_print_log();
            }
        }
    }
}

/* ---- User Task ---- */
static void user_task(void *p1, void *p2, void *p3)
{
    ARG_UNUSED(p1);
    ARG_UNUSED(p2);
    ARG_UNUSED(p3);

    struct task_identity user_id = {
        .task_id = 1,
        .privilege_level = PRIV_USER,
        .name = "user"
    };

    printk("[USER] User task started (priv=%s)\n",
           priv_to_string(user_id.privilege_level));

    /* Wait for admin to finish initialization */
    k_sleep(K_MSEC(1000));

    printk("\n[USER] === Attempting direct operations (should fail for writes) ===\n");

    /* Try direct flash write (should fail - user has no write privilege) */
    uint8_t user_data[] = {0x01, 0x02, 0x03};
    int ret = flash_write(10, user_data, sizeof(user_data), &user_id);
    printk("[USER] Direct flash write result: %d (%s)\n",
           ret, ret == 0 ? "SUCCESS" : "DENIED");

    /* Try direct config modify (should fail) */
    ret = config_modify("hostname", "hacked-device", &user_id);
    printk("[USER] Direct config modify result: %d (%s)\n",
           ret, ret == 0 ? "SUCCESS" : "DENIED");

    /* Try direct config read of public key (should succeed) */
    char value[CONFIG_VAL_LEN];
    ret = config_read("hostname", value, sizeof(value), &user_id);
    printk("[USER] Direct config read 'hostname' result: %d, value='%s'\n",
           ret, ret == 0 ? value : "N/A");

    /* Try direct config read of admin key (should fail) */
    ret = config_read("admin_key", value, sizeof(value), &user_id);
    printk("[USER] Direct config read 'admin_key' result: %d (%s)\n",
           ret, ret == 0 ? "SUCCESS" : "DENIED");

    /* Dump config as user (restricted view) */
    config_dump(&user_id);

    printk("\n[USER] === Requesting privileged operations through admin ===\n");

    /* Request 1: Flash write through admin */
    {
        struct operation_request req = {0};
        req.requester_id = user_id.task_id;
        req.requester_priv = user_id.privilege_level;
        req.operation = OP_FLASH_WRITE;
        req.flash_offset = 0x10;
        uint8_t payload[] = {0xAA, 0xBB, 0xCC, 0xDD};
        memcpy(req.data, payload, sizeof(payload));
        req.data_len = sizeof(payload);

        printk("[USER] Requesting flash write through privilege system...\n");
        ret = submit_request(&req);
        printk("[USER] Flash write request result: %d (status=%u)\n",
               ret, req.status);
    }

    k_sleep(K_MSEC(500));

    /* Request 2: Config modify through admin */
    {
        struct operation_request req = {0};
        req.requester_id = user_id.task_id;
        req.requester_priv = user_id.privilege_level;
        req.operation = OP_CONFIG_MODIFY;
        strncpy(req.config_key, "log_level", CONFIG_KEY_LEN - 1);
        strncpy(req.config_value, "debug", CONFIG_VAL_LEN - 1);

        printk("[USER] Requesting config modify through privilege system...\n");
        ret = submit_request(&req);
        printk("[USER] Config modify request result: %d (status=%u)\n",
               ret, req.status);
    }

    k_sleep(K_MSEC(500));

    /* Request 3: Read admin_key through admin (admin can read it) */
    {
        struct operation_request req = {0};
        req.requester_id = user_id.task_id;
        req.requester_priv = user_id.privilege_level;
        req.operation = OP_CONFIG_READ;
        strncpy(req.config_key, "admin_key", CONFIG_KEY_LEN - 1);

        printk("[USER] Requesting admin_key read through privilege system...\n");
        ret = submit_request(&req);
        printk("[USER] Config read request result: %d (status=%u)\n",
               ret, req.status);
        if (ret == 0) {
            printk("[USER] Received admin_key value: '%s'\n", req.config_value);
        }
    }

    k_sleep(K_MSEC(500));

    /* Request 4: Status request */
    {
        struct operation_request req = {0};
        req.requester_id = user_id.task_id;
        req.requester_priv = user_id.privilege_level;
        req.operation = OP_STATUS_REQUEST;

        printk("[USER] Requesting system status...\n");
        ret = submit_request(&req);
        printk("[USER] Status request result: %d (status=%u)\n",
               ret, req.status);
    }

    k_sleep(K_MSEC(500));

    /* Verify flash was written correctly by reading it */
    {
        uint8_t read_buf[4];
        ret = flash_read(0x10, read_buf, 4, &user_id);
        if (ret == 0) {
            printk("[USER] Flash verification at 0x10: %02x %02x %02x %02x\n",
                   read_buf[0], read_buf[1], read_buf[2], read_buf[3]);
        }
    }

    /* Verify config was modified */
    ret = config_read("log_level", value, sizeof(value), &user_id);
    if (ret == 0) {
        printk("[USER] Config verification 'log_level' = '%s'\n", value);
    }

    printk("\n[USER] === All user operations complete ===\n");

    /* User task continues running, periodically requesting status */
    while (1) {
        k_sleep(K_MSEC(10000));

        struct operation_request req = {0};
        req.requester_id = user_id.task_id;
        req.requester_priv = user_id.privilege_level;
        req.operation = OP_STATUS_REQUEST;

        printk("[USER] Periodic status check...\n");
        submit_request(&req);
    }
}

